  ?book wdt:P179 wd:Q19610143 .
  ?book wdt:P1545 "1" .
  ?book wdt:P1476 ?title .
}

SELECT ?title WHERE {
  ?book wdt:P179 wd:Q19610143 .
  ?book wdt:P1545 1 .
  ?book wdt:P1476 ?title .
}

SELECT DISTINCT ?title WHERE {
  ?book wdt:P179 wd:Q19610143 .
  ?book wdt:P1545 "1" .
  ?book wdt:P1476 ?title .
  FILTER (LANG(?title) = 'en')
}
